
import { defineComponent, onMounted, ref } from 'vue';
import { useRouter } from 'vue-router'
import TopBar from '@/components/topBar/index.vue'

export default defineComponent({
  name: 'VideoPhone',
  components: {
    TopBar
  },
  setup() {
    const router = useRouter()
    const goback = () => {
      window.ConnectWebViewBridgeSDK.goback()
    }
    const goPhone = (phone: string) => {
      if (phone === 'huawei') {
        router.push('/huawei')
      } else if (phone === 'xiaomi') {
        router.push('/xiaomi')
      } else {
        router.push('/apple')
      }
    }
    onMounted(() => {
      window.ConnectWebViewBridgeSDK.initJsBridge(function() {
        console.log()
      })
    })
    return {
      goback,
      goPhone
    };
  }
});
